import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  Button,
  CircularProgress,
  Stack,
  Alert,
  Snackbar,
  Chip
} from '@mui/material';
import {
  Refresh as RefreshIcon,
  PlayArrow as StartIcon,
  Stop as StopIcon
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, restartService } from '../services/api';

const Dashboard = () => {
  const [systemInfo, setSystemInfo] = useState(null);
  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const [info, status] = await Promise.all([
        getSystemInfo(),
        getSystemStatus()
      ]);
      setSystemInfo(info);
      setSubscriptions(status.subscriptions || []);
    } catch (err) {
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleRestart = async () => {
    try {
      setLoading(true);
      await restartService();
      setSuccess(true);
      await fetchDashboardData();
    } catch (err) {
      setError('Failed to restart service');
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const getStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case 'running':
        return 'success';
      case 'stopped':
        return 'error';
      case 'warning':
        return 'warning';
      default:
        return 'default';
    }
  };

  if (!systemInfo && loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">Operation completed successfully</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Box sx={{ mb: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h5">仪表盘</Typography>
        <Stack direction="row" spacing={2}>
          <Button
            variant="contained"
            color="primary"
            startIcon={<RefreshIcon />}
            onClick={fetchDashboardData}
            disabled={loading}
          >
            刷新
          </Button>
          <Button
            variant="contained"
            color={systemInfo?.status === 'running' ? 'error' : 'success'}
            startIcon={systemInfo?.status === 'running' ? <StopIcon /> : <StartIcon />}
            onClick={handleRestart}
            disabled={loading}
          >
            {systemInfo?.status === 'running' ? '停止' : '启动'}
          </Button>
        </Stack>
      </Box>

      <Grid container spacing={3}>
        {/* System Information */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>设备信息</Typography>
              <Stack spacing={2}>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">主机名</Typography>
                  <Typography>{systemInfo?.hostname || 'N/A'}</Typography>
                </Box>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">操作系统</Typography>
                  <Typography>{systemInfo?.platform || 'N/A'}</Typography>
                </Box>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">架构</Typography>
                  <Typography>{systemInfo?.arch || 'N/A'}</Typography>
                </Box>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">运行时间</Typography>
                  <Typography>{systemInfo?.uptime || 'N/A'}</Typography>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Service Status */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>服务状态</Typography>
              <Stack spacing={2}>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">Singbox</Typography>
                  <Stack direction="row" spacing={1} alignItems="center">
                    <Chip 
                      label={systemInfo?.singbox?.status || 'Unknown'} 
                      color={getStatusColor(systemInfo?.singbox?.status)}
                      size="small"
                    />
                    <Typography>版本: {systemInfo?.singbox?.version || 'N/A'}</Typography>
                  </Stack>
                </Box>
                <Box>
                  <Typography variant="subtitle2" color="text.secondary">Mosdns</Typography>
                  <Stack direction="row" spacing={1} alignItems="center">
                    <Chip 
                      label={systemInfo?.mosdns?.status || 'Unknown'} 
                      color={getStatusColor(systemInfo?.mosdns?.status)}
                      size="small"
                    />
                    <Typography>版本: {systemInfo?.mosdns?.version || 'N/A'}</Typography>
                  </Stack>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Subscriptions */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>订阅信息</Typography>
              <Grid container spacing={2}>
                {subscriptions.map((sub) => (
                  <Grid item xs={12} sm={6} md={3} key={sub.id}>
                    <Card variant="outlined">
                      <CardContent>
                        <Typography variant="subtitle1" gutterBottom>{sub.name}</Typography>
                        <Stack spacing={1}>
                          <Box>
                            <Typography variant="caption" color="text.secondary">更新时间</Typography>
                            <Typography variant="body2">{sub.updateTime || 'N/A'}</Typography>
                          </Box>
                          <Box>
                            <Typography variant="caption" color="text.secondary">到期时间</Typography>
                            <Typography variant="body2">{sub.expireTime || 'N/A'}</Typography>
                          </Box>
                          <Box>
                            <Typography variant="caption" color="text.secondary">流量信息</Typography>
                            <Typography variant="body2">
                              已用: {formatBytes(sub.usedTraffic || 0)} / 
                              总计: {formatBytes(sub.totalTraffic || 0)}
                            </Typography>
                          </Box>
                        </Stack>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
